const articlesDatabaseRaw = [
    {"title": "Hansi Flick: La Rinascita del Barcellona", "category": "Sport", "tag": "Analisi", "excerpt": "Hansi Flick sta trasformando il Barcellona con un gioco verticale e aggressivo. Scopriamo come.", "img": "49d833e4-f356-48d2-a531-60976e4364ba.jfif", "fullText": "Il gioco di Hansi Flick è uno dei più interessanti e curiosi d’Europa, ma chi è davvero? Hans Dieter Flick nasce in Germania, a Heidelberg, nel 1965. Intraprende la sua carriera calcistica nel 1985, al Bayern München, dove trascorre cinque anni; il suo ruolo è sempre stato il centrocampista box to box, colui che sacrifica sempre il suo corpo per essere un guerriero in campo. Nel 1990 si trasferisce al Colonia, lì non trova continuità a causa di infortuni e poco minutaggio, inoltre non viene valorizzato, si ritira proprio a Colonia a causa dei continui infortuni. Comincia così, la sua carriera da tecnico al Victoria Bammental nel 1996 e va via dopo cinque stagioni. Dopo la prima esperienza viene preso dall’Hoffenheim nel 2000 e rende bene, avendo una durata di sei anni. Nel 2006 viene preso come vice del Salisburgo alle spalle di Trapattoni. In Austria ci rimane per un solo anno, poiché dal 2006 al 2014 acquisirà le conoscenze necessarie per diventare un ottimo tecnico; in questi anni, infatti, sarà un allievo di Löw, poiché sarà vice CT della Nazionale. Il 2019 sarà per lui l’anno della svolta perché verrà preso da Niko Kovač come suo vice nel Bayern München. Nell’estate di quell’annata, però, Kovač verrà esonerato e per due anni Hansi ricoprirà il ruolo di allenatore principale. Qui tutto il mondo si rende conto della potenza di questo allenatore, valorizzando calciatori come Goretzka e facendo vivere le migliori annate calcistiche di calciatori come Robert Lewandowski e Thomas Müller. Flick sarà conosciuto per le sue goleade, ad esempio come contro il Barcellona di Leo Messi ai quarti di Champions League, battuto per 8-2; in quell'anno poi Hansi si regalerà una Champions League, che non arrivava dal 2013, una Bundesliga, un Mondiale per club, una DFB-Pokal, una DFL-Supercup e una Supercoppa Europea, collezionando così il “SEXTUPLE” che fino ad allora aveva vinto soltanto Josep Guardiola nel 2009 con il Barcellona. Nel 2022 lascerà il posto, a causa di problemi con la dirigenza, a una persona che glielo ruberà anche in nazionale, parlo di Julian Nagelsmann. Dal 2024, Flick è tecnico del Barcellona, con cui finora ha vinto una Liga, una Copa Del Rey e due Supercopa. Ora però basta parlare di biografia e passiamo all'importanza del suo gioco e la mitica linea difensiva che la passata stagione gli è costata la finale di Champions League. Il suo gioco è uno dei più offensivi e aggressivi d'Europa, ma come si sviluppa davvero? E come riesce a far valorizzare i suoi calciatori? La sua è un’evoluzione moderna con pressing alto e una rapida transizione offensiva. Partiamo dalla base, il modulo: un 4-3-3 che rapidamente in fase offensiva diventa un 2-4-4 o 2-1-3-4. Il suo gioco si concentra soprattutto con un possesso verticale; al posto del tiki taka utilizza una verticalità selettiva. I centrali difensivi si allargano e i terzini diventano ali, mentre la sua è una transizione veloce, appena persa la palla c'è un pressing ultra offensivo, chiamato Gegenpressing, che è asfissiante per tutte le squadre che lo affrontano. Sono fondamentali nel suo gioco soprattutto gli esterni, ecco perché Lamine Yamal e Raphinha sono diventati fondamentali e tra i migliori globali nel loro ruolo. Lui ha la capacità di valorizzare tutti i calciatori che servono per il suo gioco; proprio Raphinha con lui sta vivendo le annate migliori della sua carriera. Il suo gioco è concentrato anche sugli esterni con accentramento e tiro a rientrare o anche sovrapposizioni dei terzini, che diventano doppie ali. Un'altra causa per cui i calciatori rinascono con lui sono anche le alimentazioni e i carichi di lavoro. Secondo lui deve esserci una corretta e sana alimentazione con orari stabiliti per dormire; inoltre i suoi allenamenti sono concentrati su corse e sollevamento pesi in palestra, sul campo solo torelli ed esercizi con pressing altissimo. Una volta al mese le sue squadre utilizzano la maschera anti-ossigeno per effettuare una corsa e migliorare la propria capacità polmonare e respiratoria. Adesso parliamo della sua mitica linea difensiva. La difesa di Hansi Flick è quasi assente in ogni partita, o se c'è, è sempre alta. Questa tecnica può sembrare effettiva quando si imposta il gioco che si vuole e anche per far scattare il fuorigioco quasi sempre all'avversario che riceve una palla in profondità. Alcune volte però questa linea difensiva è stata calcolata male, di cui ha portato anche a opportunità sprecate, come nelle semifinali di Champions League della passata stagione contro l’Inter. Il Barça, infatti, ha subito gol calcolando male le distanze tra calciatore e avversario. L'Inter, che aveva un gioco che si sviluppava cercando quasi sempre i 2 attaccanti o gli esterni in profondità con lanci lunghi, ha saputo sfruttare bene l'errore degli avversari, facendo perdere la possibile vittoria della Champions al Barcellona. La manovra parte sempre dal basso, coinvolgendo molto il portiere e il centrocampista difensivo che si abbassa per ricevere palla e impostare il gioco verticalmente o orizzontalmente dalle ali. Il gioco di Flick è uno dei più offensivi attualmente in Europa e nel mondo, con una media di 2,45 gol a partita, la più alta d’Europa. Infine, Hansi è sempre stato un tecnico che non ha mai fallito con le squadre che ha allenato, escludendo la nazionale, di cui ha fallito alla Coppa del Mondo del 2022, uscendo ai gironi contro il Giappone.\nArticolo a cura di Antonio Guarracino"},
    {"title": "Il Parma e la presidenza Manenti", "category": "Sport", "tag": "Serie A", "excerpt": "Il ricordo della presidenza Manenti e il fallimento del Parma nel 2015.", "img": "manenti_profile.jpg", "fullText": "“Di presentazioni sobrie ne ho viste tante, ma la sua le batte tutte”.\nQuesta è una frase per chi, come me, ogni tanto non può fare a meno di rivedere una delle più iconiche e ridicole conferenze stampa del calcio italiano. Non stiamo, però, parlando né di un'intervista a Ezio Capuano e nemmeno a Alberto Malesani, ma della conferenza stampa di presentazione di Giampietro Manenti, e sì, la frase iniziale puramente ironica da parte di un giornalista. Prima di arrivare al giorno della conferenza, dell’arresto e del fallimento, ripercorriamo chi è Manenti e la situazione di quel Parma.\nManenti, prima che “imprenditore”, è stato anche giocatore e allenatore. Come giocatore è passato per Milan, Avellino e Salernitana prima che un infortunio gli spezzasse la carriera, non che fosse così promettente. È poi diventato allenatore a livelli provinciali. È titolare della MAPI, società che ha sede a Nova Gorica, in Slovenia.\nIl Parma veniva da un’ottima stagione, un ottimo sesto posto e teoricamente qualificata all’Europa League, ma di questo “teoricamente” ne parliamo a breve. Nel dietro le quinte di quel Parma, però, giocatori e staff già non stavano percependo stipendio e il Parma aveva un debito da quantomeno 100 milioni. Ritornando all’Europa League, la non iscrizione del Parma all’edizione dell’anno fu la goccia che fece traboccare il vaso e il presidente Tommaso Ghirardi fu costretto ad andarsene. La società passò a Fabio Giordano, in panchina arrivò Roberto Donadoni, che poco riuscì a fare sul campo, con la situazione societaria che si rifletteva sul campo, e Parma all’ultimo posto. A gennaio 2015 i crociati hanno un nuovo cambio ai vertici, in particolare la squadra fu acquistata da una holding cipriota, che faceva riferimento a Ermir Kodra. Da questo punto è tutta una caduta libera, alcuni giocatori, tra cui Antonio Cassano, rescissero il proprio contratto. Il 6 febbraio 2015 c’è l’ufficialità, Giampietro Manenti è il nuovo presidente del Parma, per la cifra simbolica di 1 euro.\nI tifosi inizialmente lo accolgono con speranza, è l’ultima barca per non fallire. Un primo problema si presenta subito, ci si aspettava che la nuova presidenza emettesse immediatamente dei bonifici per evitare delle penalizzazioni, ma non arriva nulla. Il giorno della conferenza stampa di presentazione è probabilmente il giorno dove si è capito che il Parma stava per fallire, Manenti si presenta con una giacca aperta color marroncino e una camicia azzurra che nel totale creavano un look che definire trasandato e poco curato è un complimento. Non si presenta da solo, con lui, i manager Alborghetti. I due rispondono alle domande in modo supponente, in difensiva, quasi offesi dal fatto che si avesse dubbi su di loro.\nLe prime domande sono sul da dove partano i fondi del presidente, il quale cita MAPI group, che sarebbe, a detta sua, in collaborazione con banche internazionali. Chiaramente MAPI in realtà è solo una grossa scatola vuota, ma a detta di Manenti avrebbe avuto anche varie branche, tra le quali gastronomia, industria e fashion. Altra domanda era relativa ai primi bonifici e quando sarebbero arrivati. Il Parma aveva una data di scadenza, datata 16 febbraio, per dimostrare la propria stabilità e disponibilità bancaria, senza illeciti, oltre che altri fondi da pagare anche prima, altrimenti penalizzazione. Manenti riguardo a ciò pare sicuro, i soldi arriveranno entro il 16 e nei giorni successivi già i primi stipendi. La preoccupazione del neo-presidente e del manager Alborghetti sembra più la retrocessione in Serie B. Iconico lo scontro tra Manenti e il giornalista Gereviri, che lo accusò di tutto, dai fondi alla serietà del progetto, Manenti, però, sempre con supponenza, si difende. Nei giorni seguenti i soldi non arrivano, il Parma riceve i primi punti di penalizzazione e Manenti viene persino aggredito da un ultras disperato del Parma.\nAlla fine, il 18 marzo 2015, Manenti e altre 22 persone vengono arrestate per crimini vari, tra cui associazione a delinquere. Il giorno seguente il Parma è dichiarato fallito e ripartirà dalla Serie D dell’anno dopo, con in panchina Nevio Scala, che vincerà la serie dilettantistica da imbattuto. Manenti rimarrà a San Vittore per poco più di due settimane, continuerà a professarsi innocente ed oggi è consulente in aziende europee. Della MAPI c’è poco da dire, la holding che investiva sulla MAPI per farne nascere altre branche è fallita e MAPI rimane una scatola vuota quanto fittizia. Oggi il Parma è in Serie A, senza debiti e con giocatori e staff stipendiati, sfornando ogni anno talenti interessanti.\nMorale della favola, non avremo mai l’onore di vestire MAPI fashion, anche se, vedendo Manenti, non credo che fosse chissà che intenditore.\nArticolo a cura di Christian Corrado"},
    {"title": "Il Maracanazo: Una Ferita Aperta", "category": "Sport", "tag": "Storia", "excerpt": "Il 16 luglio 1950 il Brasile perse il Mondiale in casa contro l'Uruguay.", "img": "maracanazo_history.jpg", "fullText": "Beauty is great for the spectators, but fight and determination win matches – La bellezza è ottima per gli spettatori, ma la lotta e la determinazione vincono le partite. Questa è la frase pronunciata da Obdulio Varela, capitano dell’Uruguay, dopo una delle partite più tragiche nell’intera storia del Brasile, ma una delle più sorprendenti nella storia dei Mondiali di calcio.\nPer capirne il motivo, bisogna ritornare indietro nel tempo al 16 luglio 1950, giorno della quarta finale della Coppa del Mondo.\nLe squadre finaliste sono il Brasile e l’Uruguay: la prima è la squadra ospitante ed è arrivata in finale senza perdere una partita, mentre l’Uruguay ha perso diversi punti per strada.\nBisogna specificare che il formato dei Mondiali del 1950 era diverso rispetto a quello attuale. Nella fase finale c’erano quattro squadre: Brasile, Uruguay, Svezia e Spagna. Il Brasile aveva vinto per 7 a 1 contro la Svezia e 6 a 1 contro la Spagna, mentre l’Uruguay aveva pareggiato a fatica con il risultato di 2 a 2 contro la Spagna e vinto 3 a 2 contro la Svezia, di conseguenza il Brasile aveva 4 punti mentre l’Uruguay ne aveva 3, quindi al Brasile serviva un pareggio per laurearsi Campione del Mondo.\nPer questo motivo, la mattina del 16 luglio a Rio de Janeiro c’è aria di festa: carri, danze, per tutto il paese il Brasile è campione del mondo, ma nel calcio non si deve mai sottovalutare l’avversario.\nSpostiamoci alla partita: sera del 16 luglio, Stadio Maracanã di Rio de Janeiro, i tifosi brasiliani sono 200.000 (record assoluto nella storia del calcio), mentre i tifosi uruguaiani sono solamente 100.\nMolti di voi si stanno chiedendo: l’Uruguay era veramente così scarso? Assolutamente no!\nSi presenta al Maracanã schierando questa formazione: Maspoli in porta, in difesa Gonzales e Tejera, a centrocampo Gambetta, Varela (il capitano, detto “il capo”) e Rodriguez Andrade, in attacco Ghiggia (detto “la volpe”), Perez, Moran, Juan Alberto Schiaffino (detto “il Dio del calcio”) e Alcide Ghiggia.\nNon può essere definita scarsa una squadra che ha in campo il “Dio del calcio”...\nIl Brasile invece schiera Barbosa in porta, in difesa Augusto, Juvenal, Bauer e Danilo, a centrocampo Bigode e Friaça, in attacco Zizinho, Ademir (capocannoniere con 8 gol), Jair e Chico.\nLa partita inizia con un boato, che sarà considerato il più grande mai sentito durante una partita di calcio.\nIl Brasile attacca mentre l’Uruguay difende con le unghie, marcando addirittura in due l’attaccante brasiliano Ademir.\nNonostante le varie conclusioni verso la porta dell’Uruguay, il primo tempo finisce 0-0, con un pizzico di delusione da parte dei 200.000 tifosi presenti al Maracanã ma, per fortuna loro, il muro dell’Uruguay cade solo dopo 68 secondi dall’inizio del secondo tempo. Ademir fugge sulla fascia e serve a Friaça che, in diagonale batte Maspoli, 1-0 Brasile.\nSembra l’inizio del sogno, ma in realtà è l’inizio dell’incubo. Al 66’ la Volpe Ghiggia scappa ancora sulla fascia e mette un cross perfetto sulla testa di Schiaffino che prima addomestica la palla e poi calcia all’incrocio, 1-1.\nNonostante il gol subito, c’è ancora aria di festa, perché il pareggio va bene per il Brasile, ma l’Uruguay ne ha ancora. Al 79’ Ghiggia scappa ancora sulla fascia: il portiere brasiliano Barbosa, aspettandosi il cross, si muove verso il secondo palo ma Ghiggia lo beffa, calciando sul primo... 2-1 Uruguay.\nIl Maracanã cala in un silenzio impressionante, mancano ancora 10 minuti più recupero, ma il Brasile non ne ha più! Finisce 2 a 1 per l’Uruguay.\nGhiggia, dopo la partita, dirà: “Solo tre persone hanno zittito il Maracanã: Frank Sinatra, Papa Giovanni Paolo II ed io.”\nPer il Brasile è una tragedia: 8 persone morte, 34 suicidi e 169 persone hanno avuto malori, anche i giocatori subiranno le conseguenze della sconfitta, l’ala Zizinho riceverà ogni 16 luglio una telefonata anonima che reciterà: “Perché abbiamo perso?” mentre il portiere Barbosa, considerato il principale colpevole, dirà: “In Brasile, la pena massima per un crimine è 30 anni. Io ne sto scontando più di 40 per un crimine che non ho commesso”.\nAl popolo, invece, le lacrime verranno cancellate da cinque future vittorie dei campionati mondiali, ma per sempre rimarrà la tragedia di una finale che era considerata già vinta.\nArticolo a cura di Francesco Castiglione"},
    {"title": "Cime Tempestose: Una Recensione", "category": "Cinema", "tag": "Recensione", "excerpt": "Il nuovo film diretto da Emerald Fennell che riprende il romanzo di Emily Brontë.", "img": "b6b5b384-4888-446b-a84e-fdd7069d6ac3.jfif", "fullText": "La pellicola che tratteremo è la nuova versione diretta da Emerald Fennell che riprende la storia del famoso romanzo scritto da Emily Brontë, considerato uno dei romanzi più importanti della letteratura inglese oltre ad essere anche il mio preferito. Questa nuova versione prova a rendere la storia ancora più complicata dal punto di vista dei sentimenti. La storia racconta il rapporto molto complicato tra Heathcliff e Catherine, due ragazzi che crescono insieme fin da piccoli. Heathcliff, infatti, non è il vero figlio della famiglia ma viene trovato per strada dal padre di Catherine che decide di adottarlo e portarlo a vivere con la famiglia. All’inizio il padre di Catherine, cioè il padrone della casa, inizia a trattare Heathcliff in modo duro, costringendolo a fare lavori pesanti e umiliandolo. Nonostante questo, Catherine continua a passare molto tempo con lui e tra i due nasce un legame molto forte. Crescendo però Catherine conosce un’altra famiglia più ricca, quella dei Linton, indu incontra Edgar e sua sorella Isabella. Edgar si innamora subito di Catherine e le promette una vita più sicura e tranquilla dal punto di vista economico e per questo Catherine decide di sposarlo anche se dentro di sé continua ad amare Heathcliff. Quando Heathcliff scopre questa decisione rimane molto offeso e decide di scappare. Dopo anni ritorna, più elegante e con un aspetto principesco, ma dentro gli rimane la rabbia. Nel frattempo anche Isabella si innamora di Heathcliff, però questo amore non sarà felice e ci fa vedere quanto Heathcliff è diventato sempre più duro. Catherine nel frattempo è sposata con Edgar e rimane incinta, ma dopo un periodo di grande stress si ammala e perde il bambino. La sua salute peggiora anche a causa di suo marito e Heathcliff, fino alla morte di Catherine. Il rapporto tra Heathcliff e Catherine è importante anche se ci sono stati vari conflitti. Heathcliff compie anche dei gesti nei confronti di Catherine; uno dei più significativi è quando rompe una sedia del tavolo per accendere il fuoco e scaldarla mentre sta male. L’aspetto importante è che quella sedia rappresenta il suo posto a tavola e romperla significa togliere il proprio posto pur di riscaldarla. Un altro personaggio molto importante è la serva Nelly, ex serva del padre di Catherine, che giudica Catherine"},
    {"title": "Scuola e videogiochi, opposti o coincidenti?", "category": "Videogiochi", "tag": "Riflessione", "excerpt": "Una riflessione su come i videogiochi come Uncharted possano essere educativi.", "img": "87e20958-928b-4d25-9252-120d9f99c40e.jfif", "fullText": "Ad oggi un po' siamo “videoludici”.\nGiochiamo per svago, per divertirci, per acculturarci e per ciò che ci insegnano. Sì, anche per ciò che ci insegnano, non solo dal punto di vista emotivo, ma anche da quello culturale e storico.\nCi sono tanti capolavori videoludici, un esempio concreto è la saga di Uncharted, nata nel 2007 per opera di Naughty Dog, casa costruttrice di proprietà Sony.\nIl primo Uncharted è Drake’s Fortune; ci troviamo nei panni di Nathan Drake, un ragazzino cresciuto in un orfanotrofio insieme al fratello maggiore Sam Drake, introdotto per la prima volta nel quarto ed ultimo gioco della saga con protagonista Nathan Drake “La fine di un ladro”.\nNathan, una volta aver abbandonato l’orfanotrofio (ormai adolescente), verrà cresciuto da Victor Sullivan (Sully) (Uncharted 3), a seguito di un borseggio per l’anello di Sir Francis Drake, pirata vissuto intorno al 1540 d.C. in Inghilterra. Da quest’ultimo si ispira proprio il personaggio di Nathan e si unisce la storia con lo svago di noi giovani. I più attenti sapranno che Sir Francis non aveva eredi; infatti, nell’ultimo titolo della saga si scoprirà che dopo essersi intrufolati all’interno di una casa, dove la mamma (Cassandra Morgan) ha lavorato anni e anni prima e aveva lasciato delle cose a cui i fratelli Drake erano affezionati e potevano riprendersi, scapperanno dalla polizia e cambieranno identità, dai fratelli Morgan ai fratelli Drake.\nBrevemente vi racconterò i quattro giochi della saga.\nNel primo gioco della saga dobbiamo riportare alla luce la mitica città di El Dorado con tutto il suo oro maledetto, appartenente alla mitologia e al folklore sudamericano.\nNel secondo gioco, dopo aver subito un tradimento da un vecchio amico, dobbiamo sterminare l’esercito di Flynn e Zoran Lazarević per trovare la via di Shambala, mito asiatico legato alla spiritualità buddhista e a un regno nascosto.\nNel terzo gioco dobbiamo trovare il tesoro di Thomas Edward Lawrence, conosciuto meglio come Lawrence d’Arabia (durante la guerra era un ufficiale britannico che operava nel Medio Oriente. Collaborò con i ribelli arabi nella Rivolta Araba, una rivolta contro l’Impero Ottomano), ma a seguito di un problema con l’ex di Sully (anche essa impegnata nella caccia al tesoro), si troveranno entrambi su un aereo che precipiterà sul deserto del Rub al-Khali (Ubar), trovando per pura casualità la città fantasma e abbandonata dopo la Prima Guerra Mondiale.\nNel quarto gioco della saga, ci troviamo in prigione con Sam ed un loro caro amico conosciuto lì, Rafe Adler. I tre effettueranno una fuga, ma Sam verrà sparato e Nathan ormai lo dà per morto; ma il gioco ci porta quindici anni più avanti, dove Nathan se lo ritroverà alla porta di casa.\nSam sa bene che Nathan aveva chiuso con i tesori e quindi per convincerlo a cercare il tesoro che da piccoli hanno sognato e studiato (anche grazie ai libri della mamma archeologa ritrovati in quella casa) di Avery e la colonia di Libertalia fondata da vari pirati, inventa che un boss l'ha fatto evadere dal carcere ed ora vuole parte di quel tesoro.\nIn seguito, Nathan sulla via per il tesoro incontrerà Rafe (che si rivelerà essere un loro nemico) e quest’ultimo dirà tutta la verità a Nathan davanti a Sam, cioè che quel boss era morto da anni e Rafe aveva pagato la cauzione a Sam ma senza voler nulla in cambio, gli aveva chiesto solo di non intromettersi in questa vicenda del tesoro.\nUncharted è un pezzo d’infanzia che è nel cuore di tutti noi giocatori; potrei rigiocarlo un milione di volte senza mai stancarmi. La storia dei pirati, di Drake, Avery, Anne Bonny ed altri merita di essere studiata; lo studio merita di essere collegato allo svago, alle passioni e alla gioia di noi giovani adolescenti.\nUn altro esempio concreto è la saga di Assassin’s Creed, creata da Ubisoft nel 2007, leggermente prima di Uncharted. Attualmente i capitoli principali sono quattordici, ma con gli spin-off si arriva anche a venti.\nAd esempio, nella saga Ezio Collection ci troviamo nel Medioevo Rinascimentale, nei panni di un giovane di nome Ezio Auditore, originario della Repubblica Fiorentina (Firenze).\nEzio all’inizio non è un assassino; lo diventerà in seguito alla morte del padre e dei due fratelli, impiccati ingiustamente davanti al pubblico di Firenze e traditi dall’avvocato Umberto corrotto dalla famiglia rivale De' Pazzi. Nel gioco incontreremo vari personaggi storici; tra i più celebri troviamo Leonardo da Vinci, un caro amico di Ezio, così tanto da prestargli armi che realmente ha creato lui. Successivamente Ezio verrà incaricato dalla madre Maria di proteggere la famiglia De' Medici, con a capo Lorenzo De' Medici, detto il Magnifico.\nEzio diventerà un assassino per portare avanti la dinastia e la confraternita degli assassini, spiegata bene in Assassin’s Creed Origins.\nAssassin’s Creed Odyssey invece è ambientato nell’antica Grecia (V secolo a.C.), un titolo molto dettagliato di cui si impara tantissimo su tutta la mitologia greca.\nQuesti giochi oltre a storie mitologiche e medievali mi hanno insegnato personalmente i valori nell’amare una persona che merita veramente.\nSì, è ovvio che giocare tanto può nuocere alla salute o comunque può “incollarci ad uno schermo”, ma con moderazione ed unita magari allo studio o comunque al nostro bagaglio culturale può migliorare concentrazione, logica ma soprattutto la voglia di studiare.\nIn conclusione? Spero che quest’articolo che ho scritto con tanta voglia e passione lo legga qualche prof per unire studio e divertimento; mi piacerebbe davvero tanto sentire qualche prof che colleghi queste due cose. Inoltre mi sento di consigliare agli studenti di giocare titoli che possano farci imparare qualcosa, non solo di storia, ma emotivamente, non solo i titoli che ho citato in questo articolo, ma anche titoli come:\nGod of War, Call of Duty (consiglio il WWII), Kingdom Come: Deliverance, anche Detroit: Become Human, ma soprattutto il mio preferito Red Dead Redemption II.\nN.B.\nLa saga di Uncharted oltre a questi titoli di cui vi ho parlato comprende anche Golden Abyss, uscito nel 2011/2012, dove Nathan sarà alla ricerca della città d’oro di Quivira sulle montagne dell’America Centrale (le sette città dell’oro).\nNell’ultimo capitolo di tutta la saga “L’eredità perduta” (The Lost Legacy) ci troviamo nei panni di Chloe Frazer, ex di Nathan, che alleata con Nadine Ross (nemica dei fratelli Drake in Uncharted 4 e alleata di Rafe Adler), dovrà trovare la zanna di Ganesh per poi salvare Sam Drake nonostante l’odio con Ross; si impara molto sulla mitologia indiana.\nVi lascio con qualche frase iconica delle due saghe di cui vi ho parlato:\n“Tutti gli uomini sognano, ma non tutti allo stesso modo. Coloro che sognano di notte, nei polverosi recessi della mente, si svegliano al giorno seguente scoprendo che era solo vanità; ma i sognatori diurni sono uomini pericolosi, perché possono agire il loro sogno a occhi aperti, rendendolo possibile. Questo l’ho fatto io.”\n“Fai attenzione a ciò che desideri. Potresti ottenerlo davvero.”\nNathan Drake.\nSIC PARVIS MAGNA (motto di Sir Francis Drake)\n“Nulla è vero, tutto è lecito”\n“Reagisci, impara, migliora. Non c’è altro modo.”\nEzio Auditore.\nArticolo a cura di Christian Damone"},
    {"title": "La Bellavita di Artie 5ive", "category": "Musica", "tag": "Recensione Album", "excerpt": "Recensione dell'album 'La Bellavita' pubblicato nel 2025.", "img": "5e7b36fc-95b0-4cb1-afcc-89e43938d108.jfif", "fullText": "Questo progetto espone la fame del successo dell’artista. Il titolo dell’album rappresenta l’obiettivo che ha raggiunto il cantante. Quest’album è stato pubblicato nel 2025 e ha collezionate ben 2 dischi di platino. Andiamo a vedere le varie tracce:\nLa prima traccia è “Intro” e riflette sulla ricerca di una vita lussuosa e sulla sua crescita personale rappresentando i suoi cambiamenti (“la bellavita sulle colline”)\nLa seconda traccia è “Montecarlo” in cui utilizza la località citata nel titolo per dimostrare il raggiungimento di una vita agiata grazie alla musica, siccome Montecarlo è una città molto ricca \nLa terza traccia è “Brazy”, in questo brano troviamo il feat con Tony Boy, tra questa canzone e quella precedente, ossia Montecarlo, troviamo una transition che li lega, dal punto di vista del significato non ne ha uno preciso ma è per lo più per “gasare”, ed è molto simile al genere americano\nLa quarta traccia è “Ogni amico mio” in cui racconta della vita dell’artista dal punto di vista dell’amicizia, in quanto nonostante che lui e i suoi amici non avevano niente sono rimasti sempre uniti.\nLa quinta traccia è “Sogno americano”, in questa traccia l’artista esprime il motivo di rivalsa personale raccontando il suo percorso di vita \nLa sesta traccia è “FW/SS25”, su questo brano possiamo dire che celebra il successo, ma niente di che siccome si tratta di un freestyle\nLa settima traccia è “Tu”, si tratta di una canzone che parla d’amore e l’artista esprime il concetto di una brutta relazione, in quanto lui viene sempre preso per il cattivo della situazione \nL’ottava traccia è “Are U Crazy?” per quanto mi riguarda è la melodia più bella che abbia mai sentito in vita mia, il ritornello è forte e ripetuto con alternanza tra Artie 5ive e Capo Plaza, artista con cui ha fatto il feat, e continua a rappresentare “Tu” ma parla dell’aspetto più bello.\nLa nona traccia è “Dodge Durango” un po' per come è avvenuto per il titolo della canzone “Montecarlo” anche questa canzone l’artista prende spunto da un esempio reale, in questo caso la dodge durango che sarebbe una macchina abbastanza costosa, per esprimere la sua ricchezza e popolarità\nLa decima traccia è “Litorale”, una canzone con cui troviamo il feat con Guè, questa canzone esprime l’umiltà dell’artista e racconta che molti rapper vengono presi per dei gangster, ma lui si definisce come un imprenditore “Sono rapper però apro due aziende”\nL’undicesima traccia è “Davverodavvero”, in questa traccia l’artista esprime il momento in cui riesce a raggiungere il successo, citando anche da dove viene\nLa dodicesima traccia è “Milano Ferragosto”, in questo brano l’artista fa riferimento alla città di Milano a ferragosto, quando la città è deserta, e utilizza ciò come una metafora in quanto l’artista si sente vuoto e solo nonostante il successo.\nLa tredicesima traccia è “Pietà”, in questa traccia troviamo il feat con Kid Yugi, parla principalmente del comportamento di alcune persone che si vantano o comunque si sentono superiori nonostante non abbiano nulla mentre Artie 5ive nonostante la sua ricchezza e popolarità rimane comunque umile. Per esprimere tutto ciò troviamo anche alcune barre in cui dice che lui è un imprenditore e non un gangster, e che non ha bisogno di vantarsi perché i suoi successi parlano da soli.\nArticolo a cura di Felice De Vita"},
    {"title": "Anche gli eroi muoiono - Kid Yugi", "category": "Musica", "tag": "Recensione Album", "excerpt": "Il ritorno di Kid Yugi con un album crudo e introspettivo.", "img": "8d8e509c-61fc-4221-9be2-bab2057a5e86.jfif", "fullText": "Francesco Stasi in arte Kid Yugi, rapper pugliese che ci mette tutto se stesso per farsi capire, è alto due metri, ha scritto il suo primo album \"The globe\" (2022) poi Quarto di bue (2023) e “Tutti i nomi del diavolo” (2024). Dopo \"tutti i nomi del diavolo\" si prende un anno di pausa e torna con questo capolavoro intitolato \"Anche gli eroi muoiono\". L'album comincia con \"L'ultimo a cadere\", una canzone dove lui parla di alcuni insuccessi e cercherà di essere l'ultimo a cadere. Questa canzone a me non piace perché si sente troppo autotune; dopodiché troviamo subito un featuring con Shiva intitolato: \"la violenza necessaria\". Il pezzo con Shiva è eccezionale perché è crudo e va dritto al punto. L’autore non fa troppi giri di parole e dice chiaramente che in certi posti o mangi o vieni mangiato, e che a volte alzare la voce o fare la faccia tosta è l'unico modo per non farsi mettere i piedi in testa.\nLa terza traccia si chiama Eroina feat tutti i fenomeni, una canzone più concentrata sull'amore dove menziona le parole Eroina e Cocaina; per questo ha suscitato uno scandalo alla radio, perché davanti ai soldi non è riuscito a trattenersi e ha cambiato la parola medicina.\nProcediamo poi con la quarta intitolata \"Jolly\"; il ritornello dice: “Il mio credo è soldi, soldi, soldi, mentre voi ammazzate lo scappo con i lingotti”. Dice che ora è il tempo dei soldi come se minimizzasse l'essere umano. La quinta traccia è un feat questa volta con Tony Boy intitolata: “Mostro”, dove parlano delle loro ex frequentazioni che li hanno resi dei mostri e dicono che anche questi ultimi soffrono. La sesta traccia è stata il primo spoiler prima che uscisse l'album, pura rap intitolata: “Berserker”; mi piace molto e cita Belen, De André e Ken di Barbie. La settima è un altro feat con Artie 5ive in \"Push it\", sempre rap, menziona la sua ex ed è stata la seconda canzone spoilerata prima dell'uscita dell'album. L'ottava è \"Amelie\", che io non preferisco, ed è una canzone dedicata ad una ragazza conosciuta a Parigi ma che non si chiama Amelie. La nona traccia è “Gilgamesh”, un’altra canzone pura rap che cita Ginnor, Checco e Justin Bieber con Clay Thompson.\nNell'undicesima traccia troviamo “Chuck Norris”, un altro feat con Papa V e RRari dal Tacco; una curiosità su questa canzone è che la parte finale è tutta in pugliese. La dodicesima si chiama \"Tristano e Isotta\", ispirata allo storico romanzo di Chrétien de Troyes o di Béroul, e in una barra dice \"Il nostro amore che ci uccide alla Tristano e Isotta\"; io la amo ed è una delle mie preferite. La prossima è \"Mu'ammar Gheddafi\", che si rifà al colonnello e dittatore della Libia; anche questa è un feat con Simba La Rue. Successivamente troviamo l'ultimo feat, con Artie 5ive: “bullet ballet”, puro rap, ed è la mia preferita. Cita Artie 5ive e l'idi di marzo. La quattordicesima intitolata \"per il sangue versato\" è una canzone che parla di due ragazzi di due quartieri diversi evidenziando la differenza tra le loro vite.\nLa penultima traccia si chiama \"Per te che lotto\", dedicata ad una ragazza per cui prova un amore così forte da lottare per esso. L'ultima, la più bella, \"Davide e Golia\", ispirata al racconto biblico del più forte contro il più debole, tratta molti argomenti come: guerra, prigione, attori, bomba nucleare, dieta, tossici e molti altri. Questo è il mio album preferito, vi consiglio di ascoltarlo grazie dell'attenzione.\n\nTRACKLIST & BIO\n1. L'ultimo a cadere\n2. La violenza necessaria (feat Shiva)\n3. Eroina (feat tutti i fenomeni)\n4. Jolly\n5. Mostro (feat Tony Boy)\n6. Berserker\n7. Push it (feat Artie 5ive)\n8. Amelie\n9. Gilgamesh\n10. Chuck Norris (feat Papa V e RRari dal tacco)\n11. Tristano e Isotta\n12. Mu'ammar Gheddafi (feat Simba La Rue)\n13. Bullet Ballet (feat Artie 5ive)\n14. Per il sangue versato\n15. Per te che lotto\n16. Davide e Golia\n\nArticolo a cura de Vincenzo Pirozzi"},
    {"title": "Dolce Vita - Shiva", "category": "Musica", "tag": "Recensione Album", "excerpt": "L'album della rivincita per il rapper di Corsico.", "img": "0ee88205-fa7f-40d1-afd2-0966d7a6f364.jfif", "fullText": "Dolce vita è il terzo album in studio del rapper italiano Shiva, pubblicato l’11 giugno 2021 dalla Milano Ovest (la sua casa discografica). Dura esattamente 42 minuti, con 14 tracce, di cui 2 solo in digitale (Fendi Belt –feat Paky- e Non sai niente –feat Gue-), etichettato da Sony Musica, Columbia e da Milano Ovest. Certificato disco di platino con oltre 50.000 copie vendute, si è classificato sesto nella classifica del 2021. Shiva, classe '99, tra il 2014 e il 2017 si afferma come “next big thing” del rap italiano. Nel 2019 inizia il suo boom, con collaborazioni importanti come Emis Killa e Sfera Ebbasta. Nel 2020 vive un anno difficile, ma Dolce Vita diventa l’album della rivincita.\n\nTRACCE\nDolce Vita, la prima traccia dell’album, colpisce perché sin da subito il cantante parla della sua rivincita, di come dal niente è diventato così importante. Il sound è molto forte, fa capire con quanta forza lui vuole riprendersi quello che ha perso. I Can Fly racconta che dalle strade e dal niente arriva a girare su macchine di lusso; tante persone non credevano in lui, ma non ha mai mollato. Mastercard (feat. Lil Baby), terza traccia, è una delle più importanti internazionali di Shiva, parlando di strada e successo con un tocco di attrazione globale. \n\nIdee Chiare è una delle più belle dell’album, raccontando di come tanti ragazzi della sua età siano morti cercando il successo. Collane e Bugie parla di come Shiva sia passato dall’avere niente a catene costose, restando fedele alla strada. Superstar riflette sul percorso verso il successo e sulla solitudine che la fama può portare. Megatron e Problema mostrano il lato più aggressivo e determinato del rapper, affrontando sfide con resistenza. La mia storia, nona traccia, è una delle più significative: con un beat lento, Shiva racconta la sua vita nelle strade di Corsico senza un padre.\n\nArticolo a cura di Roberta Guarino"},
    {"title": "Heroes & Villains - Metro Boomin", "category": "Musica", "tag": "Recensione Album", "excerpt": "Un viaggio cinematografico tra eroi e cattivi.", "img": "8d0b2472-63a9-4251-92ea-2f468cb2595e.jfif", "fullText": "Nel 2021, Metro Boomin ha annunciato l’album attraverso una lettera di DJ Holiday. Il 16 dicembre 2022, per il suo 29° compleanno, ha pubblicato il trailer con tutti i featuring. Nonostante i ritardi dovuti ai campionamenti, l’album è andato subito virale grazie a grandi collaborazioni come Travis Scott, tornato dopo lo scandalo di Astroworld. Nel 2023 è stato uno dei dischi più venduti.\n\nOn Time, con John Legend, introduce l’album in modo cinematografico, dividendo il mondo tra eroi e cattivi. Segue Superhero (con Future e Chris Brown), che parla delle difficoltà superate e del successo che attrae l’attenzione. Too Many Nights con Don Toliver ha un beat rilassante e riflette sulle lunghe notti di lavoro necessarie per raggiungere la vetta. Raindrops, con il ritorno di Travis Scott, utilizza la metafora della pioggia di diamanti per descrivere la ricchezza ottenuta. Trance affronta il tema dell’attrazione, non solo estetica ma legata anche allo status e al successo.\n\nAround Me riflette sulle persone che si avvicinano solo per interesse, mentre Creepin’ con The Weeknd e 21Savage (la traccia più ascoltata) parla della difficoltà di avere una vita privata sotto i riflettori e di relazioni tossiche. Infine, All The Money con Gunna riassume lo stile di vita descritto in tutto l’album: il lusso, le spese folli ma anche i sacrifici partendo dalla povertà. Heroes & Villains non è solo la vita di Metro Boomin, ma lo stile di vita di un'intera generazione di artisti che hanno lottato per il successo.\n\nTRACKLIST\n1. On Time (con John Legend)\n2. Superhero (con Future e Chris Brown)\n3. Too Many Nights (con Future feat. Don Toliver)\n4. Raindrops (con Travis Scott)\n5. Umbrella (con Travis Scott e Young Nudy)\n6. Trance (con Travis Scott e Young Thug)\n7. Around Me (feat. Don Toliver)\n8. Metro Spider (con Young Thug)\n9. I Can’t Save You (interlude) (con Future feat. Don Toliver)\n10. Creepin’ (con The Weeknd e 21Savage)\n11. Niagara Falls (con Travis Scott e 21Savage)\n12. Walk Em Down (con 21Savage feat. Mustafa)\n13. Lock On Me (con Travis Scott e Future)\n14. Feel The Fiyaaaah (con A$AP Rocky feat. Takeoff)\n15. All The Money (con Gunna)"},
    {"title": "Intervista: Prof.ssa Ferraro", "category": "Attualità Segrè", "tag": "Intervista", "excerpt": "Quattro chiacchiere con Rossella Ferraro sulla passione per l'informatica.", "img": "chip_informatica.jpg", "fullText": "“Perché ha scelto di insegnare informatica?”\n“Perché rispecchia un po' i miei interessi, che avevo sin delle scuole superiori, e quindi ho portato avanti questa mia passione per poi trasformarla nel mio lavoro.”\n“Qual è il metodo migliore per insegnare informatica agli studenti?”\n“È far parte del loro mondo, capire qual è il loro linguaggio, il loro punto di vista e cercare di confrontarsi per arrivare a loro, in tutti i modi possibili.”\n“Secondo lei, quale linguaggio di programmazione è più utile imparare per iniziare?”\n“Non è un vero e proprio linguaggio di programmazione, è un linguaggio che consente di imparare quali sono i processi per arrivare alla programmazione.”\n“Cosa consiglia agli studenti che trovano difficile la programmazione?”\n“Allora, innanzitutto quella di chiedere al prof di classe, perché a volte anche le domande fatte da più alunni diversi fanno comprendere al professore quale argomento non è chiaro, non solo allo studente ma alla classe. E poi anche confrontarsi con i compagni che può rendere più semplice la comprensione grazie al rapporto in comune, che è differente con quello del professore.”\n“Va bene prof, grazie mille.”\n“Figuratevi, è stato un piacere.”\n\nArticolo a cura di Adele Del Fiore e Vanessa Apuzzo"},
    {"title": "Intervista: Prof. Russo", "category": "Attualità Segrè", "tag": "Intervista", "excerpt": "Il ruolo di docente e vicepreside tra responsabilità e sfide.", "img": "ufficio_vicepreside.jpg", "fullText": "“Com'è conciliare il ruolo di docente con quello di vicepreside?”\n“Non sempre semplice, però penso di riuscirci abbastanza bene.”\n“Assolutamente sì prof.”\n“La seconda domanda: qual è la responsabilità più grande che sente nel suo ruolo?”\n“Allora, secondo me la gestione dei rapporti interpersonali, che secondo me sono importantissimi, quindi saper gestire a stare dalla parte dei ragazzi, docenti e soprattutto della preside, che non sempre è semplice.”\n“Dal suo punto di vista, quali sono le principali sfide della scuola oggi?”\n“Sfida fondamentale è che ogni alunno deve avere la possibilità di credere nelle proprie potenzialità, e non avvilirsi, perché i problemi si affrontano un passo alla volta.”\n“C’è una decisione presa come vicepreside che ricorda con particolare emozione?”\n“A questa domanda posso dirvi solo sì, ma non posso andare oltre per una questione di privacy.”\n“Va benissimo prof, la ringraziamo e a presto.”\n“Grazie a voi ragazze.”\n\nArticolo a cura di Vanessa Apuzzo e Adele Del Fiore"},
    {"title": "Intervista: Prof. Farina", "category": "Attualità Segrè", "tag": "Intervista", "excerpt": "Matematica, fisica e il futuro dell'Intelligenza Artificiale.", "img": "matematica_fisica.jpg", "fullText": "“La matematica è spesso temuta dagli studenti. Secondo lei, da cosa nasce questa difficoltà?”\n“Allora, secondo me questa difficoltà degli studenti verso la matematica è dovuta al fatto che, fondamentalmente, per studiare questo tipo di materia bisogna avere già una certa passione di base. Inoltre, c’è bisogno di una grande quantità di tempo per assimilare bene i concetti. Questa è la prima risposta che mi viene.”\n“Io parlo da studentessa: secondo me contano anche molti esercizi, perché poi la pratica rende migliori.”\n“Sì, sì, esattamente. C’è bisogno di tanta esercitazione e bisogna avere anche una passione, un amore di base verso questa materia per poi rendere al massimo.”\n“Qual è la soddisfazione più grande nel vedere un alunno progredire nella sua materia?”\n“Allora, sicuramente il nostro mestiere è quello di insegnare e trasferire le nostre conoscenze a voi studenti. È ovvio che nel momento in cui ci sono buoni risultati da parte degli studenti, il loro successo formativo diventa anche il nostro successo, perché vuol dire che abbiamo lavorato bene. Soprattutto in materie come matematica e fisica, dove è un po’ più difficile trasferire le nostre nozioni. Se uno o più ragazzi riescono bene in queste materie, siamo contenti anche di noi stessi perché vuol dire che abbiamo messo del nostro. Sicuramente noi docenti di matematica ci impegniamo tantissimo, perché non tutti imparano nella stessa maniera. Quindi lo stesso concetto deve essere rappresentato in modalità diverse, perché ogni studente ha un modo differente di apprendere. Per esempio, uno studente non impara come ho imparato io, e quindi devo fornire più strumenti per spiegare la stessa cosa affinché poi tutti capiscano quell’argomento.”\n“Quanto conta la logica nella formazione di uno studente anche al di fuori della matematica?”\n“Certo, la logica è alla base. Quando si esce dal liceo e si entra all’università, molte facoltà prevedono test di ingresso in cui la logica è fondamentale. Ma anche per qualunque tipo di concorso: i primi test, quelli che selezionano molti candidati, sono proprio test di logica e molta della logica si impara attraverso la matematica e la fisica. Il primo strumento per risolvere gli esercizi di matematica e fisica è proprio la logica, soprattutto in quelli di geometria. Già al liceo diamo degli strumenti e facciamo i primi esercizi di logica. Rispetto ad altre materie è molto diversa, ed è fondamentale.”\n“C’è stato un momento della sua carriera in cui si è sentito particolarmente orgoglioso del suo lavoro?”\n“Sì. Soprattutto in questo periodo, perché con l’avvento dell’intelligenza artificiale e delle reti neurali la figura del matematico sta diventando molto importante. Addestrare queste intelligenze artificiali significa risolvere un problema matematico che si chiama problema di minimo, che affrontiamo anche con i ragazzi del quinto anno. Recentemente sono contento perché, quando nelle classi quinte devo fare degli esempi di quello che studiamo, mi riferisco spesso all’intelligenza artificiale, che è uno dei temi più importanti e attuali.”\n“Sì, diciamo che se usata bene è utilissima.”\n“Sì, esattamente. Per voi studenti di oggi e lavoratori di domani c’è una grande scommessa: portare avanti le tecnologie di adesso. Se prima l’umanità faceva dei passi avanti ogni dieci anni, per voi il divario sarà molto minore, perché utilizzerete strumenti potentissimi. Raggiungerete grandi traguardi anche perché, se avete una difficoltà, potete risolverla utilizzando queste tecnologie che sono molto potenti.”\n“Grazie mille prof.”\n“Grazie a voi.”\n\nArticolo a cura di Vanessa Apuzzo"},
    {"title": "Intervista: Prof.ssa Fioretto", "category": "Attualità Segrè", "tag": "Intervista", "excerpt": "L'importanza dell'inglese e i nuovi metodi di insegnamento coinvolgenti.", "img": "dizionario_inglese.jpg", "fullText": "“Quanto è importante oggi conoscere l'inglese per il futuro degli studenti?”\n“Secondo me è fondamentale perché ormai il mondo globalizzato è un mondo costantemente in connessione. Quindi, ovviamente, la lingua che ci unisce tutti è la lingua inglese. Che ci piaccia oppure no, insomma, è fondamentale conoscere una lingua che accomuni il nostro mondo con quello degli altri. Secondo me non è necessario conoscerla al cento per cento a livello grammaticale o strutturale. L'importante è riuscire nella comunicazione. Questo non vuol dire che dobbiamo parlare con i gesti, però comunque dobbiamo cercare di immergerci in quella situazione, in quella lingua, per far sì che la cosa più importante – cioè la comunicazione – riesca.”\n“Grazie. Qual è il metodo che usa per rendere le lezioni più coinvolgenti?”\n“Cerco di non focalizzarmi sulla lezione frontale, come si faceva un tempo, ma di coinvolgere i ragazzi nella spiegazione. Faccio delle domande che cercano comunque di far ragionare gli studenti, sicuramente utilizzando le nuove tecnologie digitali, per esempio la LIM oppure sfruttando qualche video, soprattutto le canzoni. La musica, appunto, è un linguaggio comune, accomuna un po' tutti e quindi è qualcosa che può far avvicinare il mondo degli studenti con quello dei docenti. Inoltre cerco di proporre qualcosa che possa effettivamente interessare gli studenti, come può essere un film, una serie TV oppure anche un libro, quindi incentivare una cultura che sia extrascolastica.”\n“Nota differenze tra l'apprendimento delle lingue oggi e in passato?”\n“Sì, sicuramente c'è differenza soprattutto nella struttura della lezione. Una volta era una lezione molto più frontale, dove anche la conversazione veniva a mancare a favore della spiegazione della grammatica. Invece adesso si cerca di integrare gli studenti nella lezione, quindi di spostare il focus dall'insegnante allo studente.”\n“Qual è l'argomento che non preferisce o che le dà più dispiacere spiegare?”\n“È una bella domanda. Credo che in generale la grammatica abbia sempre qualcosa che un po' annoia. Per esempio mi piacerebbe avere il tempo di poter insegnare la grammatica utilizzando altre metodologie (purtroppo nella scuola italiana tre ore non sono abbastanza). Però, se devo pensare a un argomento specifico, sicuramente i conditional sono quelli che mi annoiano di più spiegare.”\n“Che tra l’altro dovremmo fare tra poco.”\n“Infatti vi sto preparando proprio per quello.”\n“Grazie prof.”\n“Grazie a voi.”\n\nArticolo a cura di Adele Del Fiore e Vanessa Apuzzo"},
    {"title": "Intervista: Prof. Liccardo", "category": "Attualità Segrè", "tag": "Intervista", "excerpt": "Sviluppare lo spirito critico attraverso lo studio delle scienze naturali.", "img": "microscopio_scienze.jpg", "fullText": "“Quanto è importante sviluppare curiosità e spirito critico nello studio delle scienze?”\n“È importante, perché se non si riesce a far sì che i ragazzi possano essere interessati alla materia con curiosità, altrimenti le scienze naturali diventano una materia come tante altre che sono poco sperimentali.”\n“Ritiene che oggi gli studenti siano più o meno interessati ai temi scientifici rispetto al passato?”\n“Penso più interessati, perché si sono resi conto che quello che ci circonda non è altro che le scienze, quindi quello che si insegna a scuola è la realtà che loro vedono intorno.”\n“Qual è l’argomento che suscita sempre maggior interesse tra le sue classi?”\n“Dipende dalle classi: se parliamo di una seconda, quando si inizia a parlare della cellula c’è molto interesse; in prima invece quando se parla dell’universo c’è molta curiosità.”\n“C’è stata una scoperta scientifica che l’ha particolarmente affascinata nella sua vita?”\n“Sì, sicuramente la scoperta del DNA, che ha fatto sì che si potessero in qualche modo manipolare e quindi poter arrivare a ridurre quelle che sono le anomalie genetiche.”\n\nArticolo a cura di Vanessa Apuzzo e Adele Del Fiore"},
    {"title": "Intervista: Prof.ssa Parigiano", "category": "Attualità Segrè", "tag": "Intervista", "excerpt": "L'amore per le Lettere e l'incontro con i grandi classici.", "img": "penna_lettere.jpg", "fullText": "“Cosa le piace di più del suo lavoro?”\n“Sicuramente il contatto con i ragazzi, la severità che devo mantenere, le informazioni che devo dare e cercare di trasmettere l’amore per questa materia fondamentale.”\n“Qual è la parte più difficile dell’insegnamento?”\n“Di non oltrepassare il limite, perché alcuni ragazzi sconfinano, e noi dobbiamo sempre restare in media. Spesso non basta neanche contare fino a 10, ma dobbiamo sempre mantenere la calma che contraddistingue, perché noi siamo da esempio, anche se non è proprio semplice.”\n“Qual è l’errore più comune che fanno gli studenti quando scrivono?”\n“Assolutamente errori di grammatica, come ad esempio la l senza l'apostrofo o la 'e' senza accento.”\n“Se potesse incontrare uno scrittore del passato, chi sceglierebbe e perché?”\n“Domanda difficile, ma ultimamente mi piace molto Pirandello, perché secondo me è colui che descrive al meglio il nostro divenire, le nostre maschere e il nostro modo di essere. Certo sono molto legata anche a Leopardi e Pascoli, ma il mondo pirandelliano è il mondo che mi sta facendo capire che noi siamo sempre un divenire e non siamo statici.”\n“Va benissimo prof, grazie mille.”\n“Figuratevi, alla prossima.”\n\nArticolo a cura di Adele Del Fiore e Vanessa Apuzzo"},
    {"title": "Intervista: Mimmo", "category": "Attualità Segrè", "tag": "Intervista", "excerpt": "Dietro le quinte della scuola: il lavoro fondamentale di Mimmo.", "img": "mimmo_scuola.png", "fullText": "“Qual è il contributo più importante che offre ogni giorno alla vita della scuola?”\n“Io penso di dare un buon supporto ai ragazzi e una buona collaborazione a tutto il personale della scuola, dai docenti ai miei colleghi.”\n“Quanto è fondamentale il suo lavoro dietro le quinte per il buon funzionamento dell'istituto?”\n“Il nostro lavoro (dico nostro perché siamo in due) è fondamentale, perché senza di noi la scuola non potrebbe andare avanti. Siamo un po' il motore della scuola.”\n“Qual è l'aspetto più gratificante del suo lavoro?”\n“Vedere i ragazzi che crescono, che si formano, che diventano uomini e donne. È una bella soddisfazione.”\n“C'è un aneddoto divertente o commovente che le è capitato in questi anni di lavoro?”\n“Sì, ce ne sono tanti. Uno divertente è quando un ragazzo mi ha chiesto se ero il preside della scuola. Uno commovente è quando un ragazzo, dopo aver finito la scuola, è tornato a trovarmi per ringraziarmi di tutto quello che avevo fatto per lui.”\n“Grazie mille Mimmo, è stato un piacere.”\n“Grazie a voi, ragazze.”\n\nArticolo a cura di Adele Del Fiore e Vanessa Apuzzo"},
    {"title": "Intervista: Prof.ssa Palma", "category": "Attualità Segrè", "tag": "Intervista", "excerpt": "L'importanza del latino oggi: tra radici, grammatica e saggezza antica.", "img": "colosseo_latino.jpg", "fullText": "“Allora prof, perché studiare il latino è importante oggi?”\n“Studiare il latino è importante oggi perché non è affatto una lingua morta, anzi è più viva che mai. Il nostro italiano deriva dal latino, la grammatica italiana è tutta grammatica latina, quindi studiarlo aiuta a migliorare anche lo scritto e il parlato. Ma non si studia solo per la grammatica, ma anche per la letteratura: è l'insieme del nostro patrimonio artistico e culturale. Studiando l'humanitas di Terenzio, ad esempio, comprendiamo quel mondo di valori e sentimenti che appartengono all’uomo ancora oggi nel 2026. Significa studiare le nostre radici con uno sguardo moderno. Come dico spesso ai miei alunni: noi siamo come i nani sulle spalle dei giganti. I giganti sono gli antichi, noi siamo i nani che saliamo sulle loro spalle e abbiamo una visione del mondo ancora più proiettata verso la lontananza.”\n“Dove troviamo il latino nella vita quotidiana senza accorgercene?”\n“Tutte le volte che diciamo espressioni tipo: 'ubi maior minor cessat', 'meglio abundare quam deficere', o un semplicissimo 'ad maiora' negli auguri.”\n“O anche 'carpe diem'!”\n“Certo, anche se spesso viene usato male. 'Carpe diem' oraziano significa ottimizza il tuo tempo: se ottimizza il tempo allontani la morte e vivi profondamente. L’unica dimensione del tempo che possediamo è il presente. Il latino ci aiuta a capire questi concetti basilari per la vita di tutti i giorni.”\n“Qual è il metodo migliore per imparare a tradurre bene?”\n“Il metodo migliore è quello che riprendete dalla matematica: procedere per gradi. Se non conosco i numeri e le operazioni, non posso affrontare i problemi di geometria. È uguale: è un procedimento logico. Se parte dal semplice per arrivare al difficile. E la cosa bella è che i latini non sbagliavano mai: se traducendo viene fuori un senso che non ha senso, vuol dire che abbiamo sbagliato noi, non loro.”\n“Grazie mille prof, è stato un piacere.”\n“Grazie a voi ragazze.”\n\nArticolo a cura di Adele Del Fiore e Vanessa Apuzzo"},
    {
        "title": "God of War: L'Evoluzione di un Mito",
        "category": "Videogiochi",
        "tag": "Saghe",
        "excerpt": "Tra le saghe che hanno segnato la storia dei videogiochi, God of War occupa un posto speciale. Scopriamo l'evoluzione di Kratos.",
        "img": "god_of_war_1.jpg",
        "fullText": `Come è stato sviluppato

Tra le saghe che hanno segnato la storia dei videogiochi, God of War occupa un posto speciale. Con boss fight epiche, divinità dell’olimpo e creature mitologiche la serie ha conquistato milioni di giocatori in tutto il mondo. Al centro di tutto c’è Kratos, il guerriero spartano dalla pelle pallida e il tatuaggio rosso sul corpo, diventato uno dei personaggi più importanti del mondo videoludico. Per capire meglio da dove arriva tutto questo successo dobbiamo fare un passo indietro. Il primo God of War uscì nel 2005 su PlayStation 2 ed è stato sviluppato da Santa Monica Studio. Fin dall’inizio il team voleva creare un gioco d’azione spettacolare, con combattimenti veloci e boss enormi ispirati alla mitologia greca. Tuttavia, realizzare battaglie di questa scala su PlayStation 2 non era affatto semplice. La console aveva infatti limiti tecnici piuttosto evidenti, soprattutto per quanto riguarda memoria e potenza di calcolo. Gestire creature gigantesche sullo schermo senza rallentamenti era una vera sfida. Per questo gli sviluppatori dovettero trovare diverse soluzioni creative, come costruire i boss in più parti e usare una telecamera guidata che mostrasse le battaglie nel modo più spettacolare possibile. Un esempio è lo scontro contro l’Idra, uno dei primi boss del gioco. Nonostante i limiti della console, la creatura appare enorme e rende il combattimento molto dinamico e cinematografico. Anche l’uso dei Quick Time Events aiutava a rendere le battaglie ancora più spettacolari. Grazie a queste scelte tecniche e creative, God of War riuscì subito a distinguersi dagli altri giochi d’azione dell’epoca, diventando l’inizio di una delle saghe più amate della storia dei videogiochi.

<img class="article-reader-img" src="god_of_war_2.jpg" alt="Scontro con l'Idra in God of War" style="height:auto; margin: 20px 0;">

L’aspetto prima dello schermo

Durante lo sviluppo del gioco, anche il personaggio di Kratos subì diversi cambiamenti. All’inizio gli sviluppatori non avevano ancora deciso l’aspetto che oggi tutti conoscono. In alcune delle prime idee Kratos doveva avere un look più classico, simile a quello di un guerriero greco tradizionale, con capelli e barba. Solo più tardi il team decise di renderlo completamente diverso: la pelle pallida, dovuta alle ceneri della sua famiglia, e il tatuaggio rosso che attraversa il corpo. Questa scelta rese il personaggio molto più riconoscibile e contribuì a creare l’immagine iconica che ancora oggi rappresenta la saga di God of War.

Il patto con Ares

Un’altra caratteristica fondamentale della saga è senza dubbio la trama. La storia di Kratos è una delle ragioni principali per cui God of War è riuscito a colpire così tanti giocatori. Kratos era un generale spartano che, durante una battaglia disperata, fece un patto con Ares, il dio della guerra. In cambio della vittoria, Kratos promise di servire il dio, ricevendo in dono le celebri Lame del Caos. Tuttavia, Ares lo manipolò fino a fargli uccidere la propria famiglia. Da quel momento Kratos rimase segnato per sempre: le ceneri dei suoi cari si attaccarono alla sua pelle rendendola bianca, e il senso di colpa lo spinse a intraprendere un lungo viaggio di vendetta contro gli dei dell’Olimpo. Questa storia tragica, fatta di rabbia, dolore e desiderio di redenzione, ha reso il personaggio molto più umano e ha permesso a molti giocatori di immedesimarsi nel suo conflitto interiore.

<img class="article-reader-img" src="god_of_war_3.jpg" alt="Kratos e il suo conflitto interiore" style="height:auto; margin: 20px 0;">

Lottare contro i propri mostri

Un esempio molto chiaro di questo lato del personaggio si vede in God of War: Ascension. In questo capitolo troviamo un Kratos ancora più distrutto dal dolore e tormentato dai ricordi delle sue azioni. La storia si svolge prima degli eventi del primo gioco e mostra il protagonista mentre cerca di liberarsi dal patto con Ares. Durante il gioco Kratos deve affrontare non solo nemici e creature mitologiche, ma anche i propri demoni interiori e i sensi di colpa che lo perseguitano. Questo rende la storia ancora più intensa e mostra quanto il passato conti a pesare sulle sue scelte.

<img class="article-reader-img" src="god_of_war_4.jpg" alt="Kratos in God of War Ascension" style="height:auto; margin: 20px 0;">

Il cambiamento

Negli ultimi capitoli della saga, però, il personaggio di Kratos cambia ancora una volta. Con God of War e il suo seguito God of War Ragnarök, troviamo un Kratos molto diverso da quello del passato. Non è più soltanto il guerriero guidato dalla rabbia e dalla vendetta, ma un uomo più maturo, che cerca di lasciarsi alle spalle gli errori commessi nella sua vita. In questi giochi la storia si sposta nella mitologia norrena e introduce uno degli elementi più importanti di questa nuova fase della saga: il rapporto tra Kratos e suo figlio Atreus. Dopo la morte della moglie, i due intraprendono un viaggio per spargere le sue ceneri sulla montagna più alta dei nove regni. Durante questo percorso Kratos deve affrontare una sfida completamente diversa da quelle del passato: non solo combattere contro dei e creature mitologiche, ma imparare a essere un padre. Il rapporto con Atreus diventa il cuore della storia. Kratos cerca di insegnare al figlio come sopravvivere in un mondo pieno di pericoli, ma allo stesso tempo prova a non trasmettergli la rabbia e la violenza che hanno segnato la sua vita. Questo rende il personaggio molto più profondo e mostra un lato di Kratos che nei primi giochi si vedeva raramente. In questa nuova fase della saga, quindi, God of War non è più soltanto di vendetta, ma anche di crescita, responsabilità e cambiamento. Il viaggio di Kratos dimostra che anche chi ha commesso grandi errori può provare a diventare una persona migliore. In fondo, il messaggio più importante della storia è proprio questo: siamo noi a decidere chi vogliamo essere, gli errori del passato non ci devono condizionare.

<img class="article-reader-img" src="god_of_war_5.jpg" alt="Il cambiamento di Kratos" style="height:auto; margin: 20px 0;">

Il mio pensiero sull intera saga e perché lo consiglierei

Personalmente, la saga di God of War mi ha colpito molto, soprattutto per la sua trama. Non è soltanto un gioco pieno di azione e combattimenti spettacolari, ma racconta una storia profonda che parla di dolore, errori e cambiamento. Una delle cose che mi ha colpito di più è il personaggio di Kratos. Nel corso dei vari giochi lo vediamo cambiare molto: da guerriero consumato dalla rabbia e dalla vendetta a una persona più matura che cerca di fare le scelte giuste, soprattutto per suo figlio. In alcuni aspetti mi rispecchio anche nel suo personaggio, perché Kratos dimostra che tutti possono commettere errori, ma questo non significa che il nostro futuro sia già deciso. Nel corso della saga cerca di migliorare e di diventare una persona diversa, e questo è un messaggio molto forte. Consiglierei questa saga non solo a chi ama i videogiochi d’azione, ma anche a chi cerca una storia capace di far riflettere. God of War infatti non è solo intrattenimento: attraverso il viaggio di Kratos fa capire quanto sia importante imparare dal proprio passato e provare sempre a migliorarsi. Proprio per questo penso che sia una saga che, in un certo senso, può anche cambiare il modo di pensare di chi la gioca.`
    },
    {"title": "Aftersun: Ricordi e Melancolia", "category": "Cinema", "tag": "Recensione", "excerpt": "Un viaggio emotivo tra padre e figlia, tra mare e salute mentale.", "img": "aftersun_movie_poster_1773352108336.png", "fullText": "Il film di oggi si intitola \"Aftersun\" di Charlotte Wells ed è uno dei miei film preferiti. Parla principalmente di salute mentale e del rapporto padre-figlia. Il film racconta di una vacanza in Grecia tra un giovane padre e sua figlia di dodici anni. Apparentemente questa può sembrare una semplice e tranquilla vacanza, ma quello che la ragazza non sa è che questo sarà l’ultimo momento che passerà con suo padre e gli ultimi ricordi che avrà di lui.\n\nDurante questo viaggio la ragazza avrà le sue prime esperienze; invece, suo padre si renderà conto di aver trasmesso a sua figlia la sua malattia mentale. Nel film viene menzionata molto spesso la nonna della ragazza, e si intuisce che i suoi genitori non sono più insieme. Nel corso della vacanza si può notare che viene girata una specie di documentario per volontà della bambina; infatti, si può vedere in alcuni frame la ragazza cresciuta che riguarda questi video, rivedendo i suoi ultimi momenti con suo padre.\n\nA parer mio, questo film aumenta la consapevolezza di come le malattie mentali possano essere trasmesse geneticamente e di come i bei momenti che passiamo con chi amiamo, anche senza rendercene conto, possano essere gli ultimi. Inizialmente può sembrare il solito film banale, noioso e con la solita storia, ma con il passare del tempo si capisce come questa storia abbia qualcosa di più, ovvero l'affetto profondo tra i due protagonisti.\n\nDunque, in conclusione, questo film è uno dei miei preferiti proprio perché tratta temi che molto spesso non vengono menzionati. Mi ha lasciato la consapevolezza di come il suicidio non sia la soluzione migliore, perché oltre ad uccidere noi stessi, uccidiamo anche chi ci ama di più. Una volta finito, lascia a tutti qualcosa di significativo: i brevi momenti che passiamo con chi amiamo possono essere gli ultimi, e bisogna goderseli al massimo."},
    {"title": "Tredici Pietro: Non Guardare + Giù", "category": "Musica", "tag": "Recensione Album", "excerpt": "Il figlio d'arte Pietro Morandi si racconta nel suo album più introspettivo.", "img": "tredici_pietro.jfif", "fullText": "Classe del ‘97 e figlio d’arte, Pietro, “Tredici” come gli amici della comitiva che ha deciso di portare con sé nel suo nome, si è sempre distinto dal padre, Gianni Morandi, nello stile, volendo crearsi una strada da zero come rapper fino ad arrivare sul palco dell’Ariston nella 76° edizione del Festival di Sanremo, esibendosi proprio col padre durante la serata cover.\n\nL'ALBUM: NON GUARDARE + GIÙ\n\nNON GUARDARE GIÙ: Singolo che dà il titolo all’album per una buona ragione. Racconta di come siamo tutti parte di un oceano profondo dove i forti sono i deboli e gli amici demoni, Pietro è la luce nell'oscurità dell’abisso, togliendo la maschera a chi si finge qualcuno che non è.\nmorire: Un brano forte, l’artista raccoglie tutto l’odio ricevuto da chi non ha mai creduto in lui e lo restituisce con gli interessi in modo crudo e diretto. Riassume perfettamente lo spirito di rivalsa e la determinazione che ha segnato il suo percorso musicale.\nEMIRATES: Una ragazza con infinite possibilità nella vita si isola. La sua mente il suo unico ostacolo, la sua unica gabbia, questa è la premessa di “EMIRATES” che coglie perfettamente una delle problematiche più diffuse nei ragazzi al giorno d’oggi.\nLikethisLikethat: Brano all’apparenza leggero, offre in realtà una visuale introspettiva sulle relazioni difficili narcotizzate da fumo e alcol.\nTEMPESTA: Metafora della vita che ha alti e bassi. È un inno alla crescita personale vista attraverso il momento migliore di una coppia, paragonandolo ai loro momenti più bui.\nSEMPREtardi: Canzone che parla di relazioni tossiche, dove l’amore viene sopraffatto dal senso di inadeguatezza.\nverità: Un omaggio velato a chiunque lo abbia reso la persona che è diventata, contrapponendo poi questa gratitudine all’asprezza di una sua “lei” che non gli ha mai dato ciò di cui aveva bisogno.\nLA FRETTA: Ci ricorda che siamo umani, che non dobbiamo avere paura di fallire e che non dobbiamo nasconderci davanti agli altri per i nostri errori.\nuomo che cade: Un grido di scuse di chi si è messo in gioco ed ha avuto il coraggio di cadere per risalire. Come dice Pietro, il pezzo “parla di una relazione, ma in realtà parla di me, di te, di tutti”.\nMILANOcollane: L’artista raffigura e fa coesistere la vita bolognese, sua città natale, con l’immaginario musicale milanese.\nGALLEGGIARE: Pietro usa la metafora del “galleggiare” per parlare del sentimento di impotenza che ti tiene fermo mentre la vita scorre.\nrespirare: Il brano raffigura vividamente la paura di esporsi, dove lo scrittore chiede alla sua metà di liberarsi e lasciarsi andare con lui.\n$OLDI DENARO MONETA CA££££HH: Una critica sociale al consumismo della società di oggi, dettata da denaro e potere.\nServe Amore: Fa capire che tutta la vita gira attorno all’amore e che la mancanza di quest’ultimo porta al desiderio.\nTRADIRti: Parla di tutte quelle storie finite che non si riescono a superare, mostrando le emozioni forti che provano entrambe le persone."},
    {"title": "Uncharted: L'Avventura su Grande Schermo", "category": "Cinema", "tag": "Recensione Film", "excerpt": "Tom Holland e Mark Wahlberg portano Nathan Drake e Sully al cinema.", "img": "uncharted_new.jfif", "fullText": "Cercate un film di avventura e ladri, ispirato ad un gioco e che vi distolga dalla realtà per qualche ora? Allora Uncharted fa per voi. Diretto da Ruben Fleischer, con Tom Holland nei panni di Nathan Drake e Mark Wahlberg nei panni di Victor Sullivan, il film ci presenta ladri in cerca del tesoro di Ferdinando Magellano e della sua ciurma “i famigerati 18”.\n\nPer trovarlo servono due chiavi a forma di croce: una era del capitano e una della ciurma, in possesso di Chloe, una ladra furba di cui non fidarsi. L'altra è all'asta e toccherà a Nathan Drake e Victor Sullivan rubarla, ma a mettergli i bastoni fra le ruote ci sarà il casato dei Moncada, guidato da Santiago Moncada (Antonio Banderas), che pensa che la croce sia loro di diritto.\n\nNathan Drake è un ragazzo appassionato di storia come il fratello, scappato anni prima, mentre Victor Sullivan è un ladro di cui inizialmente non ci si può fidare. Tuttavia, Sullivan alla fine del film si redime sacrificando l’oro per salvare Nathan. Questo ci insegna che non importa quanti sbagli facciamo: avremo sempre la possibilità di redimerci e dimostrare di essere migliori. Venendo ricompensati non con beni materiali, ma con amore, gentilezza e amicizia. Vi consiglio vivamente di guardarlo, per capire cosa può insegnare o semplicemente per distrarvi con una grande avventura."}
];

const articlesDatabase = articlesDatabaseRaw.map((a, i) => ({ 
    ...a, 
    id: `art-${i}`,
    link: `articolo.html?id=art-${i}`
}));

document.addEventListener('DOMContentLoaded', () => {
    const sidebar = document.getElementById('sidebar');
    const toggleBtn = document.getElementById('toggleBtn');
    const searchBtnIcon = document.getElementById('searchBtnIcon');
    const searchInput = document.getElementById('searchInput');
    const searchSubmit = document.getElementById('searchSubmit');

    // Function to toggle the sidebar
    const toggleSidebar = () => {
        if (!sidebar) return;
        const isExpanded = sidebar.classList.toggle('expanded');
        if (toggleBtn) toggleBtn.setAttribute('aria-expanded', isExpanded);
        if (isExpanded && searchInput) {
            setTimeout(() => { searchInput.focus(); }, 400);
        } else if (searchInput) {
            searchInput.blur();
        }
    };

    if (toggleBtn) toggleBtn.addEventListener('click', toggleSidebar);
    if (searchBtnIcon) searchBtnIcon.addEventListener('click', toggleSidebar);

    // ==========================================
    // LOGICA PAGINA CATEGORIA
    // ==========================================
    const categoryContainer = document.getElementById('categoryArticlesContainer');
    if (categoryContainer) {
        let currentCategory = "";
        const pathname = window.location.pathname.toLowerCase();
        if (pathname.includes('cinema.html')) currentCategory = 'Cinema';
        else if (pathname.includes('sport.html')) currentCategory = 'Sport';
        else if (pathname.includes('musica.html')) currentCategory = 'Musica';
        else if (pathname.includes('videogiochi.html')) currentCategory = 'Videogiochi';
        else if (pathname.includes('attualita-segre.html')) currentCategory = 'Attualità Segrè';

        if (currentCategory) {
            const categoryArticles = articlesDatabase.filter(a => a.category === currentCategory);
            if (categoryArticles.length > 0) {
                let htmlContent = '';
                categoryArticles.forEach((article, index) => {
                    htmlContent += `
                        <a href="${article.link}" class="article-card" style="animation-delay: ${index * 0.1}s">
                            <div class="article-image" style="background-image: url('${article.img}');"></div>
                            <div class="article-content">
                                <span class="article-tag">${article.tag}</span>
                                <span class="article-tag" style="background:#0F3859; margin-left:5px;">${article.category}</span>
                                <h2 class="article-title">${article.title}</h2>
                                <p class="article-excerpt">${article.excerpt}</p>
                            </div>
                        </a>
                    `;
                });
                categoryContainer.innerHTML = htmlContent;
            } else {
                categoryContainer.innerHTML = `<div style="grid-column: 1 / -1; text-align: center; padding: 50px;"><h2 style="color: var(--accent-red); margin-bottom: 20px;">Nessun articolo per questa categoria.</h2></div>`;
            }
        }
    }

    // ==========================================
    // LOGICA PAGINA RISULTATI RICERCA
    // ==========================================
    const searchResultsContainer = document.getElementById('searchResultsContainer');
    if (searchResultsContainer) {
        const urlParams = new URLSearchParams(window.location.search);
        const query = urlParams.get('q')?.toLowerCase() || "";
        const headerTitle = document.getElementById('searchHeaderTitle');
        
        if (query) {
            if (headerTitle) headerTitle.textContent = `Risultati per: "${query}"`;
            
            const results = articlesDatabase.filter(article => 
                article.title.toLowerCase().includes(query) ||
                article.excerpt.toLowerCase().includes(query) ||
                article.category.toLowerCase().includes(query) ||
                (article.fullText && article.fullText.toLowerCase().includes(query))
            );

            if (results.length > 0) {
                let htmlContent = '';
                results.forEach((article, index) => {
                    htmlContent += `
                        <a href="${article.link}" class="article-card" style="animation-delay: ${index * 0.1}s">
                            <div class="article-image" style="background-image: url('${article.img}');"></div>
                            <div class="article-content">
                                <span class="article-tag">${article.tag}</span>
                                <span class="article-tag" style="background:#0F3859; margin-left:5px;">${article.category}</span>
                                <h2 class="article-title">${article.title}</h2>
                                <p class="article-excerpt">${article.excerpt}</p>
                            </div>
                        </a>
                    `;
                });
                searchResultsContainer.innerHTML = htmlContent;
            } else {
                searchResultsContainer.innerHTML = `<div style="grid-column: 1 / -1; text-align: center; padding: 50px;"><h2 style="color: var(--text-blue); opacity: 0.5;">Nessun risultato trovato per "${query}".</h2></div>`;
            }
        }
    }

    const performSearch = () => {
        if (!searchInput) return;
        const query = searchInput.value.trim();
        if (query) window.location.href = `risultati.html?q=${encodeURIComponent(query)}`;
    };

    if (searchSubmit) searchSubmit.addEventListener('click', performSearch);
    if (searchInput) {
        searchInput.addEventListener('keypress', (e) => { if(e.key === 'Enter') performSearch(); });
    }

    // ==========================================
    // LOGICA VISUALIZZAZIONI
    // ==========================================
    const COOLDOWN_MS = 10 * 60 * 1000; 
    const API_NAMESPACE = 'ilpostino_official_v1_live_v2';

    const incrementViewWithCooldownAsync = async (counterName, timestampKey) => {
        let lastVisitTime = parseInt(localStorage.getItem(timestampKey)) || 0;
        const now = Date.now();
        try {
            if (now - lastVisitTime > COOLDOWN_MS) {
                const res = await fetch(`https://api.counterapi.dev/v1/${API_NAMESPACE}/${counterName}/up`);
                const data = await res.json();
                localStorage.setItem(timestampKey, now);
                return data.count;
            } else {
                const res = await fetch(`https://api.counterapi.dev/v1/${API_NAMESPACE}/${counterName}/`);
                if (res.ok) {
                    const data = await res.json();
                    return data.count;
                } else return 0;
            }
        } catch (e) {
            let localViews = parseInt(localStorage.getItem(counterName)) || 0;
            if (now - lastVisitTime > COOLDOWN_MS) {
                localViews++;
                localStorage.setItem(counterName, localViews);
                localStorage.setItem(timestampKey, now);
            }
            return localViews;
        }
    };

    const mainContent = document.querySelector('.main-content');
    if (mainContent && !document.querySelector('.global-view-counter')) {
        const viewCounterDiv = document.createElement('div');
        viewCounterDiv.className = 'global-view-counter';
        viewCounterDiv.innerHTML = `<span class="metric-icon">👁️</span><span class="metric-value" id="viewCount">...</span>`;
        mainContent.parentNode.insertBefore(viewCounterDiv, mainContent);
    }

    const viewCountEl = document.getElementById('viewCount');
    if (viewCountEl) {
        incrementViewWithCooldownAsync('site_views_real', 'last_visit_global_time').then(v => { viewCountEl.textContent = v.toLocaleString('it-IT'); });
    }

    // ==========================================
    // LOGICA PAGINA SINGOLO ARTICOLO
    // ==========================================
    const articleReader = document.getElementById('articleReader');
    const articleError = document.getElementById('articleError');
    if (articleReader) {
        const urlParams = new URLSearchParams(window.location.search);
        const articleId = urlParams.get('id');
        const article = articlesDatabase.find(a => a.id === articleId);

        if (article) {
            articleReader.style.display = 'block';
            if (articleError) articleError.style.display = 'none';
            document.title = `${article.title} - Il Postino`;
            document.getElementById('articleTitle').textContent = article.title;
            document.getElementById('articleTag').textContent = article.tag;
            document.getElementById('articleCategory').textContent = article.category;
            document.getElementById('articleImg').src = article.img;
            
            const body = document.getElementById('articleBody');
            if (article.fullText) {
                body.innerHTML = article.fullText.split('\n').filter(l => l.trim()).map(p => `<p>${p}</p>`).join('');
            }

            const articleViewEl = document.getElementById('articleViewCount');
            if (articleViewEl) {
                incrementViewWithCooldownAsync(`views_real_${article.id}`, `last_visit_real_${article.id}`).then(v => { articleViewEl.textContent = v.toLocaleString('it-IT'); });
            }

            const likeBtn = document.getElementById('articleLikeBtn');
            const likeCountEl = document.getElementById('articleLikeCount');
            const storageKey = `likes_real_${article.id}`;
            const userLikedKey = `user_liked_real_${article.id}`;

            fetch(`https://api.counterapi.dev/v1/${API_NAMESPACE}/${storageKey}/`)
                .then(res => res.ok ? res.json() : {count: 0})
                .then(data => { likeCountEl.textContent = data.count.toLocaleString('it-IT'); });

            if(localStorage.getItem(userLikedKey) === 'true') {
                if (likeBtn) likeBtn.classList.add('liked');
                const heartIcon = likeBtn ? likeBtn.querySelector('.heart-icon') : null;
                if (heartIcon) heartIcon.textContent = '❤️';
            }

            if (likeBtn) {
                likeBtn.addEventListener('click', () => {
                    const heartIcon = likeBtn.querySelector('.heart-icon');
                    let currentlyLiked = localStorage.getItem(userLikedKey) === 'true';
                    if (currentlyLiked) {
                        localStorage.setItem(userLikedKey, 'false');
                        likeBtn.classList.remove('liked');
                        if (heartIcon) heartIcon.textContent = '🤍';
                        fetch(`https://api.counterapi.dev/v1/${API_NAMESPACE}/${storageKey}/down`).then(res => res.json()).then(d => { if(likeCountEl) likeCountEl.textContent = d.count.toLocaleString('it-IT'); });
                    } else {
                        localStorage.setItem(userLikedKey, 'true');
                        likeBtn.classList.add('liked');
                        if (heartIcon) heartIcon.textContent = '❤️';
                        fetch(`https://api.counterapi.dev/v1/${API_NAMESPACE}/${storageKey}/up`).then(res => res.json()).then(d => { if(likeCountEl) likeCountEl.textContent = d.count.toLocaleString('it-IT'); });
                    }
                });
            }
        } else {
            if (articleReader) articleReader.style.display = 'none';
            if (articleError) articleError.style.display = 'block';
        }
    }
});
